{
  "name": "Manual Técnico U.E.E Jorge Semidey",
  "description": "Una guía interactiva completa sobre mantenimiento preventivo y correctivo para los equipos de la Unidad Educativa Estatal Jorge Semidey, desarrollada por estudiantes de la UPT Aragua."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import Home from './views/Home';
import Community from './views/Community';
import Introduction from './views/Introduction';
import Components from './views/Components';
import Tools from './views/Tools';
import Glossary from './views/Glossary';
import Credits from './views/Credits';

const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [showWelcome, setShowWelcome] = useState(true);
  const [showScrollTop, setShowScrollTop] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setShowScrollTop(window.scrollY > 300);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const toggleDarkMode = () => {
    setIsDarkMode(!isDarkMode);
    document.body.classList.toggle('dark-mode');
  };

  const menuItems = [
    { path: '/', label: 'Inicio' },
    { path: '/comunidad', label: 'Comunidad' },
    { path: '/introduccion', label: 'Introducción' },
    { path: '/componentes', label: 'Componentes' },
    { path: '/herramientas', label: 'Herramientas' },
    { path: '/glosario', label: 'Glosario' },
    { path: '/creditos', label: 'Créditos' },
  ];

  return (
    <div className={`min-h-screen ${isDarkMode ? 'dark-mode' : 'bg-[#f6f9ff]'}`}>
      {/* Side Menu (Mobile) */}
      <div className={`fixed top-0 left-0 h-full w-64 bg-[#1a73e8] z-[5000] transition-transform duration-300 p-6 ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <h2 className="text-white text-2xl font-bold mb-6">Menú</h2>
        <nav className="flex flex-col gap-4">
          {menuItems.map((item) => (
            <Link 
              key={item.path} 
              to={item.path} 
              className="text-white text-lg hover:underline"
              onClick={() => setIsMenuOpen(false)}
            >
              {item.label}
            </Link>
          ))}
        </nav>
      </div>
      {isMenuOpen && (
        <div className="fixed inset-0 bg-black/50 z-[4999]" onClick={() => setIsMenuOpen(false)} />
      )}

      {/* Welcome Modal */}
      {showWelcome && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-[9999] p-4">
          <div className="bg-white dark:bg-[#2a2a2a] p-8 rounded-xl max-w-sm w-full text-center shadow-2xl animate-in fade-in zoom-in duration-300">
            <h2 className="text-2xl font-bold mb-4 text-[#0b63d6]">¡Bienvenido!</h2>
            <p className="text-gray-600 dark:text-gray-300 mb-6">
              Gracias por visitar el Manual Técnico Interactivo.<br />
              Usa el menú lateral, modo oscuro y las interacciones añadidas.
            </p>
            <button 
              className="bg-[#d32f2f] text-white px-6 py-2 rounded-lg hover:bg-[#b71c1c] transition-colors"
              onClick={() => setShowWelcome(false)}
            >
              Cerrar
            </button>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="sticky top-0 z-40 bg-gradient-to-r from-[#0b63d6] to-[#1a73e8] text-white py-4 px-6 shadow-lg">
        <div className="max-w-[1100px] mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <img src="https://picsum.photos/seed/edu/100/100" className="w-12 h-12 rounded-lg" alt="Logo" />
            <div>
              <h1 className="text-lg font-bold leading-tight">Manual Técnico Interactivo</h1>
              <div className="text-xs opacity-90">U.E.E Jorge Semidey — Guía de mantenimiento</div>
            </div>
          </div>

          <nav className="hidden lg:flex items-center gap-4">
            {menuItems.map((item) => (
              <Link 
                key={item.path} 
                to={item.path} 
                className={`px-3 py-2 rounded-lg font-semibold text-sm transition-colors ${location.pathname === item.path ? 'bg-white/20' : 'hover:bg-white/10'}`}
              >
                {item.label}
              </Link>
            ))}
          </nav>

          <div className="flex items-center gap-3">
            <button className="dark-btn bg-[#333] hover:bg-[#444] text-white px-3 py-2 rounded text-xs font-bold" onClick={toggleDarkMode}>
              {isDarkMode ? 'Modo claro' : 'Modo oscuro'}
            </button>
            <button className="lg:hidden text-2xl" onClick={() => setIsMenuOpen(true)}>☰</button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-[1100px] mx-auto py-8 px-4">
        {children}
      </main>

      {/* Scroll Top Button */}
      {showScrollTop && (
        <button 
          className="fixed bottom-6 right-6 bg-[#0066ff] text-white w-12 h-12 rounded-full shadow-xl flex items-center justify-center text-2xl z-[2000] hover:scale-110 transition-transform"
          onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
        >
          ↑
        </button>
      )}

      <footer className="mt-12 py-8 text-center text-gray-500 text-sm border-t border-gray-200 dark:border-gray-800">
        Manual Técnico — UPT ARAGUA Federico Brito Figueroa © 2025 · <span className="font-bold">PNF Informática</span>
      </footer>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <HashRouter>
      <Layout>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/comunidad" element={<Community />} />
          <Route path="/introduccion" element={<Introduction />} />
          <Route path="/componentes" element={<Components />} />
          <Route path="/herramientas" element={<Tools />} />
          <Route path="/glosario" element={<Glossary />} />
          <Route path="/creditos" element={<Credits />} />
        </Routes>
      </Layout>
    </HashRouter>
  );
};

export default App;

import React, { useState } from 'react';

const Tools: React.FC = () => {
  const [search, setSearch] = useState('');

  const sections = [
    {
      title: '1. Cortar y sujetar',
      tools: [
        { name: 'Pinzas de corte', desc: 'Para seccionar cables finos y terminales metálicos.', tags: 'alicates corte' },
        { name: 'Mini alicate de punta', desc: 'Manipular piezas pequeñas en espacios reducidos.', tags: 'punta precision' },
      ]
    },
    {
      title: '2. Atornillar',
      tools: [
        { name: 'Destornillador de trinquete', desc: 'Mecanismo de ratchet para mayor velocidad.', tags: 'ratchet' },
        { name: 'Destornilladores de precisión', desc: 'Para tornillería pequeña en laptops y móviles.', tags: 'rojos precision' },
      ]
    },
    {
      title: '3. Apertura y manipulación',
      tools: [
        { name: 'Herramientas tipo spudger', desc: 'Palancas plásticas para abrir carcasas sin daño.', tags: 'spudger palanca' },
        { name: 'Extractor DIP', desc: 'Para circuitos integrados sin doblar pines.', tags: 'extractor chip' },
      ]
    },
    {
      title: '4. Soldadura',
      tools: [
        { name: 'Soldador eléctrico', desc: 'Calienta punta para fundir estaño.', tags: 'cautin' },
        { name: 'Bomba desoldadora', desc: 'Retirar estaño derretido por vacío.', tags: 'succion' },
      ]
    },
    {
      title: '5. Redes y cables',
      tools: [
        { name: 'Crimpeadora / Pelacables', desc: 'Multifunción para terminales y cables.', tags: 'crimping' },
        { name: 'Ponchadora RJ45', desc: 'Instalar conectores de red ethernet.', tags: 'rj45 ponchadora' },
      ]
    }
  ];

  return (
    <div className="space-y-8">
      <section className="bg-white dark:bg-[#2a2a2a] p-8 rounded-xl shadow-md">
        <h2 className="text-2xl font-bold text-[#0b63d6] mb-4">Buscador de Herramientas</h2>
        <div className="max-w-md">
          <input 
            type="text" 
            className="w-full px-4 py-3 border-2 border-gray-100 dark:border-gray-800 rounded-xl bg-gray-50 dark:bg-gray-800 outline-none focus:border-[#0b63d6] transition-colors"
            placeholder="Ej: Destornillador..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-[1fr,400px] gap-8">
        <div className="space-y-8">
          {sections.map((section, sIdx) => {
