                <div className="space-y-6">
                  {filteredTools.map((tool, tIdx) => (
                    <div key={tIdx} className="flex gap-4 items-start border-b border-gray-100 dark:border-gray-800 pb-4 last:border-0">
                      <img src={`https://picsum.photos/seed/tool${sIdx}${tIdx}/120/120`} className="w-20 h-20 object-cover rounded shadow" alt={tool.name} />
                      <div>
                        <h4 className="font-bold text-gray-800 dark:text-gray-100">{tool.name}</h4>
                        <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">{tool.desc}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
