        <aside className="space-y-6">
          <div className="bg-[#0b63d6] text-white p-6 rounded-xl shadow-lg">
            <h4 className="font-bold mb-4">Equipos de Diagnóstico</h4>
            <div className="space-y-4">
              <div className="flex gap-3">
                <img src="https://picsum.photos/seed/multimeter/100/100" className="w-16 h-16 rounded bg-white/10" alt="Multimetro" />
                <div>
                  <p className="font-bold text-sm">Multímetro / Tester</p>
                  <p className="text-xs opacity-80">Medir voltaje, corriente y resistencia.</p>
                </div>
              </div>
              <div className="flex gap-3">
                <img src="https://picsum.photos/seed/lan/100/100" className="w-16 h-16 rounded bg-white/10" alt="Red" />
                <div>
                  <p className="font-bold text-sm">Probador de Red LAN</p>
                  <p className="text-xs opacity-80">Verificar cables ethernet RJ45.</p>
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white dark:bg-[#2a2a2a] p-6 rounded-xl shadow-md border border-[#0b63d6]/10">
            <h4 className="text-[#0b63d6] font-bold mb-4">Protección ESD</h4>
            <img src="https://picsum.photos/seed/strap/400/200" className="w-full h-32 object-cover rounded mb-3" alt="Pulsera" />
            <p className="text-xs text-gray-600 dark:text-gray-400">
              <strong>Pulsera Antiestática:</strong> Esencial para no dañar memorias RAM o procesadores por descargas del cuerpo humano.
            </p>
          </div>
        </aside>
      </div>
    </div>
  );
};

export default Tools;

import React, { useState } from 'react';

const Glossary: React.FC = () => {
  const [search, setSearch] = useState('');

  const terms = [
    { t: 'Aislamiento', d: 'Material que evita el paso de corriente eléctrica.', letter: 'A' },
    { t: 'Amperaje', d: 'Intensidad de corriente en un circuito.', letter: 'A' },
    { t: 'Arranque', d: 'Proceso de inicio de un sistema.', letter: 'A' },
    { t: 'Batería', d: 'Almacena energía química para convertirla en eléctrica.', letter: 'B' },
    { t: 'Bitácora', d: 'Registro detallado de eventos técnicos.', letter: 'B' },
    { t: 'Cableado', d: 'Conjunto de cables para energía o datos.', letter: 'C' },
    { t: 'Capacitor', d: 'Almacena energía en forma de campo eléctrico.', letter: 'C' },
    { t: 'Correctivo', d: 'Acción realizada tras una falla.', letter: 'C' },
    { t: 'Diodo', d: 'Permite paso de corriente en una dirección.', letter: 'D' },
    { t: 'Diagnóstico', d: 'Proceso para identificar causas de falla.', letter: 'D' },
    { t: 'EPP', d: 'Equipos de Protección Personal.', letter: 'E' },
    { t: 'Fusible', d: 'Elemento de seguridad ante sobrecorriente.', letter: 'F' },
    { t: 'Multímetro', d: 'Instrumento para medir voltaje y resistencia.', letter: 'M' },
    { t: 'Potencia', d: 'Energía consumida o entregada por tiempo.', letter: 'P' },
    { t: 'Redundancia', d: 'Duplicación de elementos por seguridad.', letter: 'R' },
    { t: 'Voltaje', d: 'Fuerza que impulsa la corriente eléctrica.', letter: 'V' },
  ];

  const groupedTerms = terms.reduce((acc, item) => {
    if (!acc[item.letter]) acc[item.letter] = [];
    if (item.t.toLowerCase().includes(search.toLowerCase())) {
      acc[item.letter].push(item);
    }
    return acc;
  }, {} as Record<string, typeof terms>);

  return (
    <div className="space-y-8">
      <section className="bg-white dark:bg-[#2a2a2a] p-8 rounded-xl shadow-md">
        <h2 className="text-2xl font-bold text-[#0b63d6] mb-6">Glosario de Términos</h2>
        <div className="max-w-md mb-8">
          <input 
            type="text" 
            className="w-full px-4 py-3 border-2 border-gray-100 dark:border-gray-800 rounded-xl bg-gray-50 dark:bg-gray-800 outline-none focus:border-[#0b63d6] transition-colors"
            placeholder="Buscar término..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>

        <div className="space-y-12">
          {Object.entries(groupedTerms).sort().map(([letter, items]) => (
            items.length > 0 && (
              <div key={letter} className="relative pl-8">
                <div className="absolute left-0 top-0 text-3xl font-bold text-[#0b63d6]/20">{letter}</div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {items.map((item, idx) => (
                    <div key={idx} className="group p-4 rounded-lg hover:bg-blue-50 dark:hover:bg-blue-900/10 transition-colors">
                      <h4 className="font-bold text-[#1a73e8] mb-1">{item.t}</h4>
                      <p className="text-sm text-gray-500 dark:text-gray-400">{item.d}</p>
                    </div>
                  ))}
                </div>
              </div>
            )
          ))}
        </div>
      </section>

      <section className="bg-white dark:bg-[#2a2a2a] p-8 rounded-xl shadow-md">
        <h3 className="text-xl font-bold text-[#0b63d6] mb-4">Abreviaturas comunes</h3>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 text-xs text-gray-500 font-bold uppercase">
          <div className="p-2 border rounded">PC — Computador</div>
          <div className="p-2 border rounded">TI — Tecnología</div>
          <div className="p-2 border rounded">UPS — Respaldo</div>
          <div className="p-2 border rounded">LED — Diodo Luz</div>
          <div className="p-2 border rounded">CPU — Procesador</div>
          <div className="p-2 border rounded">RAM — Memoria</div>
          <div className="p-2 border rounded">SSD — Disco Sólido</div>
          <div className="p-2 border rounded">ESD — Estática</div>
        </div>
      </section>
    </div>
  );
};

export default Glossary;

import React, { useState } from 'react';
import { Link } from 'react-router-dom';

const Introduction: React.FC = () => {
  const [activeStep, setActiveStep] = useState(0);

  const steps = [
    { title: 'Seguridad', desc: 'Área despejada y pulsera antiestática.', icon: '🛡️' },
    { title: 'Apertura', desc: 'Retirar tornillos y carcasas con cuidado.', icon: '🔓' },
    { title: 'Limpieza', desc: 'Aire comprimido y brocha antiestática.', icon: '🧹' },
    { title: 'Pasta Térmica', desc: 'Aplicación en procesador y chipset.', icon: '🌡️' },
    { title: 'Cierre', desc: 'Ajuste de componentes y prueba final.', icon: '✅' },
  ];

  return (
    <div className="space-y-10 animate-in slide-in-from-bottom-4 duration-500">
      {/* Concept Box */}
      <section className="bg-gradient-to-br from-blue-600 to-blue-800 rounded-3xl p-8 text-white shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-8 opacity-10 text-9xl">⚙️</div>
        <h2 className="text-3xl font-bold mb-4">El Mantenimiento como Pilar</h2>
        <p className="text-blue-100 text-lg max-w-2xl mb-6">
          Es el conjunto de acciones técnicas para conservar equipos en estado óptimo, garantizando la continuidad educativa en la <span className="font-bold">U.E.E Jorge Semidey</span>.
        </p>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {[
            { t: 'Evitar Fallas', i: '🚫' },
            { t: 'Vida Útil', i: '⏳' },
            { t: 'Ahorro', i: '💰' },
            { t: 'Eficiencia', i: '🚀' }
          ].map((obj, i) => (
            <div key={i} className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/20 text-center">
              <div className="text-2xl mb-1">{obj.i}</div>
              <div className="text-xs font-bold uppercase tracking-tighter">{obj.t}</div>
            </div>
          ))}
        </div>
      </section>

      {/* Interactive Stepper */}
      <section className="bg-white dark:bg-[#2a2a2a] p-8 rounded-3xl shadow-lg border border-gray-100 dark:border-gray-800">
        <h3 className="text-2xl font-bold text-[#0b63d6] mb-8 text-center uppercase tracking-widest">Protocolo de Acción Paso a Paso</h3>

        <div className="flex justify-between items-center mb-12 relative">
          <div className="absolute h-1 bg-gray-100 dark:bg-gray-800 left-0 right-0 top-1/2 -translate-y-1/2 z-0"></div>
          {steps.map((step, i) => (
            <button 
              key={i} 
              onClick={() => setActiveStep(i)}
              className={`relative z-10 w-12 h-12 rounded-full font-bold transition-all duration-300 ${activeStep === i ? 'bg-blue-600 text-white scale-125 shadow-lg shadow-blue-200' : 'bg-white dark:bg-gray-700 text-gray-400 border-2 border-gray-100 dark:border-gray-800'}`}
            >
              {i + 1}
            </button>
          ))}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-center bg-gray-50 dark:bg-gray-800/50 p-6 rounded-3xl">
          <div className="animate-in fade-in slide-in-from-left-4 duration-500">
            <div className="text-5xl mb-4">{steps[activeStep].icon}</div>
            <h4 className="text-2xl font-bold text-gray-800 dark:text-white mb-2">{steps[activeStep].title}</h4>
            <p className="text-gray-500 dark:text-gray-400 text-lg">{steps[activeStep].desc}</p>
            <div className="mt-6 flex gap-2">
              <span className="px-3 py-1 bg-blue-100 text-blue-600 rounded-full text-xs font-bold">Crítico</span>
              <span className="px-3 py-1 bg-green-100 text-green-600 rounded-full text-xs font-bold">Verificado</span>
            </div>
          </div>
          <div className="relative group overflow-hidden rounded-2xl">
            <img 
              src={`https://picsum.photos/seed/step${activeStep}/600/400`} 
              className="w-full aspect-video object-cover transition-transform duration-700 group-hover:scale-110" 
              alt={steps[activeStep].title} 
            />
          </div>
        </div>
      </section>

      <div className="text-center pb-8">
        <Link to="/herramientas" className="inline-flex items-center gap-2 bg-[#0b63d6] text-white px-10 py-5 rounded-full font-extrabold shadow-xl hover:scale-105 transition-all">
          Ver Kit de Herramientas <span className="text-xl">🛠️</span>
        </Link>
      </div>
    </div>
  );
};

export default Introduction;

