    { t: 'MOTHERBOARD', d: 'Placa de circuito impreso principal que interconecta todos los componentes del sistema informático.' },
    { t: 'MOSFET', d: 'Transistor de efecto de campo metal-óxido-semiconductor. Utilizado para la conmutación de potencia en placas madre.' },
    { t: 'NORTHBRIDGE', d: 'Puente Norte. Chip encargado de gestionar el tráfico entre el CPU, la memoria RAM y el bus gráfico.' },
    { t: 'OXIDACIÓN', d: 'Reacción química en la que un átomo o ion cede electrones. En hardware, degrada los contactos de cobre y plata.' },
    { t: 'PASTA TÉRMICA', d: 'Masilla que facilita la transferencia de calor entre el procesador y el disipador rellenando irregularidades microscópicas.' },
    { t: 'POST', d: 'Power-On Self-Test. Proceso de verificación inicial que realiza el computador al encenderse.' },
    { t: 'PUERTO', d: 'Punto físico de interfaz a través del cual se puede enviar o recibir datos desde o hacia un periférico.' },
    { t: 'RAM', d: 'Random Access Memory. Memoria principal de acceso aleatorio, donde se cargan los datos y programas en ejecución.' },
    { t: 'REFLOW', d: 'Técnica de reparación que consiste en recalentar las soldaduras de un componente para restaurar sus conexiones eléctricas.' },
    { t: 'REPOSITORIO', d: 'Sitio centralizado donde se almacena y mantiene información digital, habitualmente bases de datos o archivos de software.' },
    { t: 'ROOT', d: 'Nombre convencional de la cuenta de usuario que posee todos los derechos en todos los modos en sistemas operativos tipo Unix.' },
    { t: 'SATA', d: 'Serial ATA. Interfaz de transferencia de datos entre la placa base y algunos dispositivos de almacenamiento.' },
    { t: 'SMD', d: 'Surface Mount Device. Tecnología de montaje superficial de componentes electrónicos directamente sobre la placa.' },
    { t: 'SOUTHBRIDGE', d: 'Puente Sur. Chipset que gestiona los periféricos de entrada y salida de baja velocidad y almacenamiento.' },
    { t: 'SSD', d: 'Solid State Drive. Dispositivo de almacenamiento de datos que utiliza memoria no volátil para almacenar datos.' },
    { t: 'SULFATACIÓN', d: 'Acumulación de sales en las terminales metálicas producto de la humedad y corrientes galvánicas.' },
    { t: 'SWAP', d: 'Área de intercambio. Espacio en el disco duro que el sistema operativo utiliza como extensión de la memoria RAM.' },
    { t: 'TDP', d: 'Thermal Design Power. Cantidad máxima de calor que el sistema de refrigeración del computador debe disipar.' },
    { t: 'VGA', d: 'Video Graphics Array. Estándar analógico de visualización gráfica en computadores.' },
    { t: 'VOLTAJE', d: 'Diferencia de potencial eléctrico expresada en voltios. Impulsor de la corriente en un circuito electrónico.' }
  ].sort((a, b) => a.t.localeCompare(b.t));

  const filtered = terms.filter(item => {
    const matchesSearch = item.t.toLowerCase().includes(search.toLowerCase());
    const matchesLetter = activeLetter ? item.t.startsWith(activeLetter) : true;
    return matchesSearch && matchesLetter;
  });

  return (
    <div className="space-y-16 animate-in fade-in duration-700 pb-20">
      <header className="border-b-8 border-black pb-8">
        <h2 className="text-6xl font-bold italic uppercase tracking-tighter">Diccionario Técnico</h2>
        <p className="text-xl italic mt-4 opacity-70 underline decoration-blue-600">Enciclopedia de Términos de Ingeniería Informática.</p>
      </header>

      {/* Selector Alfabético Profesional */}
      <nav className="flex flex-wrap gap-1 justify-center border-y-2 border-black py-8 bg-gray-50">
         <button 
          onClick={() => setActiveLetter(null)}
          className={`px-6 py-2 font-bold uppercase transition-all border-2 border-black ${activeLetter === null ? 'bg-blue-600 text-white shadow-md' : 'bg-white hover:bg-gray-100'}`}
         >
           Ver Todo
         </button>
         {alphabet.map(letter => {
           const hasTerms = terms.some(t => t.t.startsWith(letter));
           return (
             <button 
              key={letter}
              disabled={!hasTerms}
              onClick={() => setActiveLetter(letter)}
              className={`w-10 h-10 font-bold uppercase transition-all border border-gray-200 ${!hasTerms ? 'opacity-10 cursor-not-allowed' : activeLetter === letter ? 'bg-blue-600 text-white border-blue-600 scale-110 shadow-lg' : 'bg-white hover:bg-blue-50 hover:border-blue-300'}`}
             >
               {letter}
             </button>
           );
         })}
      </nav>

      {/* Buscador de Términos */}
      <div className="max-w-2xl mx-auto">
         <input 
          type="text" 
          placeholder="Escriba aquí para buscar un término..." 
          className="w-full bg-white border-2 border-black px-8 py-4 font-bold italic outline-none focus:border-blue-600 transition-all text-center text-xl shadow-inner"
          onChange={(e) => setSearch(e.target.value)}
         />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-x-16 gap-y-12 py-10">
         {filtered.map((item, i) => (
           <div key={i} className="space-y-4 border-b border-gray-100 pb-8 hover:bg-gray-50 p-4 transition-colors">
              <h4 className="text-3xl font-bold italic text-blue-600 uppercase tracking-tighter">{item.t}</h4>
              <p className="text-lg leading-relaxed italic opacity-80 font-medium">
                {item.d}
              </p>
           </div>
         ))}
      </div>
    </div>
  );
};

