const Glossary: React.FC = () => {
  const [search, setSearch] = useState('');
  const [activeLetter, setActiveLetter] = useState<string | null>(null);

  const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ".split("");

  const terms = [
    { t: 'ACPI', d: 'Advanced Configuration and Power Interface. Estándar industrial para la gestión de energía.' },
    { t: 'BIOS', d: 'Basic Input/Output System. Programa básico grabado en el chip CMOS.' },
    { t: 'BUS', d: 'Canal de comunicación que transfiere datos entre componentes internos.' },
    { t: 'CAPACITOR', d: 'Componente pasivo capaz de almacenar energía. Vital en la regulación de voltaje.' },
    { t: 'CHIPSET', d: 'Conjunto de circuitos integrados diseñados para gestionar la memoria y periféricos.' },
    { t: 'CMOS', d: 'Almacena los datos de configuración del BIOS y la hora del sistema.' },
    { t: 'CPU', d: 'Central Processing Unit. El microprocesador principal del sistema.' },
    { t: 'DDR2', d: 'Estándar de memoria RAM utilizado en las arquitecturas Canaima legacy.' },
    { t: 'DISIPADOR', d: 'Componente metálico diseñado para evacuar el calor del procesador.' },
    { t: 'DRIVER', d: 'Software que permite al S.O. interactuar con un periférico de hardware.' },
    { t: 'ESD', d: 'Electrostatic Discharge. Descarga electrostática peligrosa para semiconductores.' },
    { t: 'EXT4', d: 'Sistema de archivos transaccional para Linux, estándar en Canaima.' },
    { t: 'FIRMWARE', d: 'Programa básico que controla los circuitos electrónicos de un dispositivo.' },
    { t: 'FLEX', d: 'Cable plano diseñado para ser flexible, usado para conectar pantallas.' },
    { t: 'FSB', d: 'Front Side Bus. Bus que conecta el microprocesador con el Chipset.' },
    { t: 'GNU', d: 'Proyecto de software libre masivo. Provee las herramientas del S.O.' },
    { t: 'GRUB', d: 'Grand Unified Bootloader. Gestor de arranque múltiple.' },
    { t: 'HDD', d: 'Hard Disk Drive. Almacenamiento magnético no volátil.' },
    { t: 'IDE/PATA', d: 'Interfaz antigua para la conexión de discos duros.' },
    { t: 'KERNEL', d: 'El núcleo de un sistema operativo. Gestiona el acceso al hardware.' },
    { t: 'LAN', d: 'Local Area Network. Red que conecta computadores en un área limitada.' },
    { t: 'LINUX', d: 'Núcleo libre de S.O. tipo Unix. Corazón de la distribución Canaima.' },
    { t: 'MOTHERBOARD', d: 'Placa base que interconecta todos los componentes del sistema.' },
    { t: 'NORTHBRIDGE', d: 'Puente Norte. Chip encargado de gestionar RAM y video.' },
    { t: 'PASTA TÉRMICA', d: 'Masilla que facilita la transferencia de calor procesador-disipador.' },
    { t: 'RAM', d: 'Random Access Memory. Memoria volátil de trabajo del sistema.' },
    { t: 'ROOT', d: 'Usuario con privilegios totales en sistemas tipo Unix/Linux.' },
    { t: 'SATA', d: 'Serial ATA. Interfaz de transferencia de datos moderna.' },
    { t: 'SMD', d: 'Surface Mount Device. Tecnología de montaje superficial.' },
    { t: 'SOUTHBRIDGE', d: 'Puente Sur. Chipset que gestiona periféricos lentos y disco.' },
    { t: 'SSD', d: 'Solid State Drive. Almacenamiento basado en memoria flash.' },
    { t: 'SWAP', d: 'Área de intercambio en disco usada como extensión de RAM.' },
    { t: 'VGA', d: 'Estándar analógico de visualización gráfica.' }
  ].sort((a, b) => a.t.localeCompare(b.t));

  const filtered = terms.filter(item => {
    const matchesSearch = item.t.toLowerCase().includes(search.toLowerCase());
    const matchesLetter = activeLetter ? item.t.startsWith(activeLetter) : true;
    return matchesSearch && matchesLetter;
  });

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      <header className="space-y-2">
        <h2 className="text-4xl font-black uppercase text-slate-900 tracking-tight">Glosario Técnico</h2>
        <p className="text-sm font-bold text-blue-600 uppercase tracking-widest">Enciclopedia de Soporte Canaima.</p>
      </header>

      <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 space-y-8">
        {/* Selector Alfabético */}
        <nav className="flex flex-wrap gap-1 justify-center">
           <button 
            onClick={() => setActiveLetter(null)}
            className={`px-4 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${activeLetter === null ? 'bg-blue-600 text-white shadow-lg' : 'bg-white text-slate-400 hover:bg-slate-100 border border-slate-100'}`}
           >
             Ver Todo
           </button>
           {alphabet.map(letter => {
             const hasTerms = terms.some(t => t.t.startsWith(letter));
             return (
               <button 
                key={letter}
                disabled={!hasTerms}
                onClick={() => setActiveLetter(letter)}
                className={`w-9 h-9 text-[11px] font-black uppercase rounded-lg transition-all ${!hasTerms ? 'opacity-20 cursor-not-allowed' : activeLetter === letter ? 'bg-blue-600 text-white scale-110 shadow-lg' : 'bg-white text-slate-500 hover:border-blue-300 border border-slate-100 shadow-sm'}`}
               >
                 {letter}
               </button>
             );
           })}
        </nav>

        {/* Buscador */}
        <div className="relative max-w-xl mx-auto">
           <input 
            type="text" 
            placeholder="Escriba aquí para buscar un término..." 
            className="w-full bg-white border-2 border-slate-100 px-8 py-4 rounded-xl font-bold text-slate-700 outline-none focus:border-blue-600 transition-all text-center text-lg shadow-sm"
            onChange={(e) => setSearch(e.target.value)}
           />
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
         {filtered.map((item, i) => (
           <div key={i} className="p-6 bg-white rounded-2xl border border-slate-100 hover:border-blue-100 hover:shadow-xl hover:shadow-blue-50/50 transition-all group">
              <h4 className="text-xl font-black text-blue-600 uppercase tracking-tighter mb-2 group-hover:scale-105 transition-transform origin-left">{item.t}</h4>
              <p className="text-sm font-medium text-slate-500 leading-relaxed">
                {item.d}
              </p>
           </div>
         ))}
      </div>
    </div>
  );
};

