// --- LOGICA DE RENDERIZADO PRINCIPAL ---

const render = () => {
  const container = document.getElementById('app-content');
  const sidebarNav = document.getElementById('sidebar-nav');
  const headerNav = document.getElementById('header-nav');

  // Renderizar navegación
  const navHtml = menuItems.map(item => `
    <a href="#${item.path}" 
       class="text-[11px] font-extrabold uppercase tracking-wider transition-colors px-4 py-2 rounded-lg 
       ${state.currentView === item.path ? 'bg-blue-50 text-blue-600' : 'text-slate-500 hover:text-blue-600'}"
       onclick="toggleMenu(false)">
       ${item.label}
    </a>
  `).join('');

  sidebarNav.innerHTML = navHtml;
  headerNav.innerHTML = navHtml;

  // Renderizar vista
  switch (state.currentView) {
    case 'inicio': container.innerHTML = renderInicio(); break;
    case 'comunidad': container.innerHTML = renderComunidad(); break;
    case 'introduccion': container.innerHTML = renderIntroduccion(); break;
    case 'componentes': container.innerHTML = renderComponentes(); break;
    case 'herramientas': container.innerHTML = renderHerramientas(); break;
    case 'glosario': container.innerHTML = renderGlosario(); break;
    case 'creditos': container.innerHTML = renderCreditos(); break;
    default: container.innerHTML = renderInicio();
  }

  // Vincular eventos post-renderizado para herramientas
  const toolBtn = document.getElementById('tool-dropdown-btn');
  if (toolBtn) {
    toolBtn.onclick = (e) => {
      e.stopPropagation();
      const menu = document.getElementById('tool-dropdown-menu');
      menu.classList.toggle('hidden');
    };
  }
};

