// --- Utilidades ---
window.toggleMenu = (open: boolean) => {
  if (open) {
    sidebar?.classList.remove('-translate-x-full');
    backdrop?.classList.remove('hidden');
  } else {
    sidebar?.classList.add('-translate-x-full');
    backdrop?.classList.add('hidden');
  }
};

const updateActiveLinks = (path: string) => {
  document.querySelectorAll('.nav-link').forEach(link => {
    const dataPath = link.getAttribute('data-path');
    if (dataPath === path) {
      link.classList.add('text-blue-600');
      if (link.classList.contains('py-2')) link.classList.add('bg-blue-50');
      link.classList.remove('text-slate-500', 'text-slate-600');
    } else {
      link.classList.remove('text-blue-600', 'bg-blue-50');
      link.classList.add(link.classList.contains('py-2') ? 'text-slate-600' : 'text-slate-500');
    }
  });
};

// --- Enrutador ---
const routes: Record<string, string> = {
  '/': 'Home.html',
  '/comunidad': 'Community.html',
  '/introduccion': 'Introduction.html',
  '/componentes': 'Components.html',
  '/herramientas': 'Tools.html',
  '/glosario': 'Glossary.html',
  '/creditos': 'Credits.html'
};

async function loadView() {
  const hash = window.location.hash.replace('#', '') || '/';
  const fileName = routes[hash] || 'Home.html';

  try {
    const response = await fetch(`./views/${fileName}`);
    if (!response.ok) throw new Error('Vista no encontrada');
    const html = await response.text();

    if (contentDiv) {
      contentDiv.innerHTML = `<div class="view-fade-in">${html}</div>`;
      window.scrollTo(0, 0);
      updateActiveLinks(hash);
      initViewLogic(hash);
    }
  } catch (err) {
    if (contentDiv) contentDiv.innerHTML = `<div class="p-20 text-center font-bold text-red-500">Error al cargar la vista.</div>`;
  }
}

// --- Lógica Específica de Vistas ---
function initViewLogic(path: string) {
  if (path === '/introduccion') initIntroduction();
  if (path === '/herramientas') initTools();
  if (path === '/glosario') initGlossary();
}

function initIntroduction() {
  window.toggleStep = (idx: number) => {
    const detail = document.getElementById(`step-detail-${idx}`);
    const icon = document.getElementById(`step-icon-${idx}`);
    const card = document.getElementById(`step-card-${idx}`);

    const isOpen = !detail?.classList.contains('hidden');

    // Cerrar todos primero
    document.querySelectorAll('[id^="step-detail-"]').forEach(d => d.classList.add('hidden'));
    document.querySelectorAll('[id^="step-icon-"]').forEach(i => i.textContent = '+');
    document.querySelectorAll('[id^="step-card-"]').forEach(c => c.classList.remove('border-blue-600', 'bg-white', 'shadow-xl', 'shadow-blue-50'));

    if (!isOpen && detail && icon && card) {
      detail.classList.remove('hidden');
      icon.textContent = '−';
      card.classList.add('border-blue-600', 'bg-white', 'shadow-xl', 'shadow-blue-50');
    }
  };
}

function initTools() {
  const dropdownBtn = document.getElementById('tools-dropdown-btn');
  const dropdownMenu = document.getElementById('tools-dropdown-menu');
  const label = document.getElementById('current-tool-cat');

  window.toggleToolsDropdown = () => {
    dropdownMenu?.classList.toggle('hidden');
  };

  window.filterTools = (catIdx: number | null, catName: string) => {
    if (label) label.textContent = catName;
    dropdownMenu?.classList.add('hidden');

    document.querySelectorAll('[id^="tool-cat-container-"]').forEach((container, idx) => {
      if (catIdx === null || catIdx === idx) {
        container.classList.remove('hidden');
      } else {
        container.classList.add('hidden');
      }
    });
  };
}

function initGlossary() {
  const searchInput = document.getElementById('glossary-search') as HTMLInputElement;
  const terms = document.querySelectorAll('.glossary-item');

  const filter = () => {
    const query = searchInput.value.toLowerCase();
    terms.forEach(term => {
      const text = term.getAttribute('data-term')?.toLowerCase() || '';
      if (text.includes(query)) {
        (term as HTMLElement).style.display = 'block';
      } else {
        (term as HTMLElement).style.display = 'none';
      }
    });
  };

  searchInput?.addEventListener('input', filter);

  window.filterGlossaryLetter = (letter: string | null) => {
    terms.forEach(term => {
      const text = term.getAttribute('data-term') || '';
      if (!letter || text.startsWith(letter)) {
        (term as HTMLElement).style.display = 'block';
      } else {
        (term as HTMLElement).style.display = 'none';
      }
    });
  };
}

// Escuchar cambios de hash
window.addEventListener('hashchange', () => {
  toggleMenu(false);
  loadView();
});

// Carga inicial
loadView();

