import React, { useState, useEffect } from 'react';

interface AssetImageProps extends React.ImgHTMLAttributes<HTMLImageElement> {
  basePath: string; // Ruta sin extensión, ej: "/assets/home/mi_foto"
}

const AssetImage: React.FC<AssetImageProps> = ({ basePath, alt, className, ...props }) => {
  // Lista de extensiones a probar en orden de prioridad
  const extensions = ['.jpg', '.png', '.jpeg', '.webp'];
  const [tryIndex, setTryIndex] = useState(0);
  const [hasError, setHasError] = useState(false);

  // Reiniciar estado si cambia la ruta base
  useEffect(() => {
    setTryIndex(0);
    setHasError(false);
  }, [basePath]);

  const handleError = () => {
    if (tryIndex < extensions.length - 1) {
      // Si falla, probar la siguiente extensión
      setTryIndex(prev => prev + 1);
    } else {
      // Si fallan todas, marcar error
      setHasError(true);
    }
  };

  if (hasError) {
    return (
      <div className={`bg-slate-100 flex flex-col items-center justify-center text-slate-400 p-4 border border-slate-200 ${className}`} style={{ minHeight: '100px' }}>
        <span className="text-[10px] font-bold uppercase tracking-widest">Imagen no encontrada</span>
        <span className="text-[8px] opacity-50 break-all text-center mt-1">{basePath}</span>
      </div>
    );
  }

  return (
    <img
      {...props}
      src={`${basePath}${extensions[tryIndex]}`}
      alt={alt}
      className={className}
      onError={handleError}
    />
  );
};

