import React, { useState, useEffect } from 'react';

interface AssetImageProps extends React.ImgHTMLAttributes<HTMLImageElement> {
  basePath: string; // Ejemplo: "assets/home/mi_foto"
}

const AssetImage: React.FC<AssetImageProps> = ({ basePath, alt, className, ...props }) => {
  const [currentSrc, setCurrentSrc] = useState<string | null>(null);
  const [hasError, setHasError] = useState(false);

  useEffect(() => {
    let isMounted = true;
    setHasError(false);
    setCurrentSrc(null);

    // Normalizar ruta: quitar slash inicial si existe para procesarlo uniformemente
    const rawPath = basePath.startsWith('/') ? basePath.slice(1) : basePath;

    // Lista de extensiones a probar
    const extensions = ['.jpg', '.png', '.jpeg', '.webp', '.JPG', '.PNG', '.JPEG', '.WEBP'];

    // Generar todas las posibles combinaciones de rutas donde podría estar la imagen
    const candidates: string[] = [];

    // 1. Ruta absoluta desde la raíz (Recomendado para servidores web)
    // Ejemplo: /assets/home/foto.jpg
    extensions.forEach(ext => candidates.push(`/${rawPath}${ext}`));

    // 2. Ruta relativa (Útil para algunos entornos locales o file://)
    // Ejemplo: assets/home/foto.jpg
    extensions.forEach(ext => candidates.push(`${rawPath}${ext}`));

    // 3. Ruta en carpeta public explícita (Fallback común)
    // Ejemplo: /public/assets/home/foto.jpg
    if (rawPath.startsWith('assets/')) {
       extensions.forEach(ext => candidates.push(`/public/${rawPath}${ext}`));
    }

    // Función recursiva para probar las imágenes una por una
    const tryLoad = (index: number) => {
      if (!isMounted) return;

      // Si ya probamos todas y ninguna funcionó
      if (index >= candidates.length) {
        setHasError(true);
        return;
      }

      const img = new Image();
      img.src = candidates[index];

      img.onload = () => {
        if (isMounted) {
          setCurrentSrc(candidates[index]);
          setHasError(false);
        }
      };

      img.onerror = () => {
        // Si falla, probar la siguiente candidata
        tryLoad(index + 1);
      };
    };

    // Iniciar la búsqueda
    tryLoad(0);

    return () => {
      isMounted = false;
    };
  }, [basePath]);

  // Estado de error: Mostrar un placeholder elegante si la imagen no existe
  if (hasError) {
    return (
      <div className={`bg-slate-100 flex flex-col items-center justify-center text-slate-400 p-4 border-2 border-dashed border-slate-200 rounded-lg ${className}`} style={{ minHeight: '100px' }}>
        <svg className="w-8 h-8 mb-2 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
        <span className="text-[10px] font-bold uppercase tracking-widest text-center">No encontrada</span>
        <span className="text-[8px] opacity-50 break-all text-center mt-1 font-mono">{basePath.split('/').pop()}</span>
      </div>
    );
  }

  // Estado de carga: Skeleton loader
  if (!currentSrc) {
     return <div className={`bg-slate-100 animate-pulse rounded-lg ${className}`} />;
  }

  // Estado de éxito
  return (
    <img
      {...props}
      src={currentSrc}
      alt={alt}
      className={`${className} transition-opacity duration-500 opacity-100`}
    />
  );
};

export default AssetImage;

