import React, { useState, useCallback, useEffect } from 'react';

interface AssetImageProps extends React.HTMLAttributes<HTMLDivElement> {
  alt?: string;
}

const AssetImage: React.FC<AssetImageProps> = ({ alt, className, ...props }) => {
  const [imageSrc, setImageSrc] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  // Generamos una clave única basada en el texto alternativo (alt)
  // para guardar la imagen en la memoria del navegador.
  const storageKey = `img_store_${alt?.replace(/[^a-zA-Z0-9]/g, '_') || Math.random().toString(36).substr(2, 9)}`;

  // Al cargar el componente, buscamos si ya hay una imagen guardada
  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        setImageSrc(saved);
      }
    } catch (e) {
      console.error("Error leyendo memoria local", e);
    }
  }, [storageKey]);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    const file = e.dataTransfer.files[0];
    if (file && file.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onload = (event) => {
        if (event.target?.result) {
          const result = event.target.result as string;
          setImageSrc(result);

          // Intentamos guardar en LocalStorage
          try {
            localStorage.setItem(storageKey, result);
          } catch (error) {
            console.error("Error guardando imagen (posiblemente muy grande):", error);
            alert("La imagen se mostrará, pero es demasiado pesada para guardarse permanentemente. Intenta con una imagen más pequeña u optimizada.");
          }
        }
      };
      reader.readAsDataURL(file);
    }
  }, [storageKey]);

  // Función para resetear la imagen (doble click)
  const handleDoubleClick = () => {
    if (imageSrc) {
      if (confirm("¿Quieres eliminar esta imagen guardada?")) {
        setImageSrc(null);
        localStorage.removeItem(storageKey);
      }
    }
  };

  if (imageSrc) {
    return (
      <img
        {...props}
        src={imageSrc}
        alt={alt || "Imagen cargada"}
        className={`${className} cursor-pointer object-cover`}
        title="Doble click para eliminar y cambiar"
        onDoubleClick={handleDoubleClick}
      />
    );
  }

  return (
    <div
      {...props}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`${className} flex flex-col items-center justify-center text-center border-4 border-dashed transition-all cursor-pointer p-4 group relative overflow-hidden
        ${isDragging 
          ? 'border-blue-500 bg-blue-50 text-blue-600 scale-[0.99]' 
          : 'border-slate-200 bg-slate-50 text-slate-400 hover:border-blue-300 hover:bg-white hover:text-blue-400'
        }`}
    >
      <div className={`transition-transform duration-300 ${isDragging ? 'scale-110' : 'group-hover:scale-110'}`}>
        <svg className="w-10 h-10 mb-2 mx-auto" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path>
        </svg>
      </div>
      <span className="text-[10px] uppercase font-black tracking-widest pointer-events-none relative z-10">
        {isDragging ? 'SUELTA AQUI' : 'ARRASTRA IMAGEN'}
      </span>
      {alt && <span className="text-[8px] mt-1 opacity-50 font-mono pointer-events-none uppercase max-w-full truncate px-2 relative z-10">{alt}</span>}
    </div>
  );
};

