    };
    loadFromDB();
    return () => { mounted = false; };
  }, [storageKey, isPermanent]);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    if (isPermanent) return; // No permitir arrastrar si ya es permanente
    e.preventDefault();
    setIsDragging(true);
  }, [isPermanent]);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    if (isPermanent) return;
    e.preventDefault();
    setIsDragging(false);

    const file = e.dataTransfer.files[0];
    if (file && file.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onload = async (event) => {
        if (event.target?.result) {
          const result = event.target.result as string;
          setImageSrc(result);
          try {
            await dbHelpers.put(storageKey, result);
          } catch (error) {
            console.error("Error guardando en BD:", error);
            alert("Error al guardar imagen temporal.");
          }
        }
      };
      reader.readAsDataURL(file);
    }
  }, [storageKey, isPermanent]);

  const handleDoubleClick = async () => {
    if (isPermanent) {
      alert("Esta imagen ya está guardada permanentemente en el código fuente (utils/permanentImages.ts). Para cambiarla, debes editar ese archivo.");
      return;
    }

    if (imageSrc) {
      if (confirm("¿Quieres eliminar esta imagen temporal?")) {
        setImageSrc(null);
        try {
          await dbHelpers.delete(storageKey);
        } catch (e) {
          console.error("Error borrando imagen", e);
        }
      }
    }
  };

  if (loading) {
    return (
      <div className={`${className} bg-slate-100 flex items-center justify-center animate-pulse`}>
        <span className="text-slate-300 text-xs">Cargando...</span>
      </div>
    );
  }

  if (imageSrc) {
    return (
      <img
        {...props}
        src={imageSrc}
        alt={alt || "Imagen cargada"}
        className={`${className} object-cover transition-opacity ${isPermanent ? '' : 'cursor-pointer hover:opacity-90'}`}
        title={isPermanent ? "Imagen Permanente (Guardada en Código)" : "Doble click para eliminar y cambiar"}
        onDoubleClick={handleDoubleClick}
      />
    );
  }

  return (
    <div
      {...props}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`${className} flex flex-col items-center justify-center text-center border-4 border-dashed transition-all cursor-pointer p-4 group relative overflow-hidden select-none
        ${isDragging 
          ? 'border-blue-500 bg-blue-50 text-blue-600 scale-[0.99]' 
          : 'border-slate-200 bg-slate-50 text-slate-400 hover:border-blue-300 hover:bg-white hover:text-blue-400'
        }`}
    >
      <div className={`transition-transform duration-300 ${isDragging ? 'scale-110' : 'group-hover:scale-110'}`}>
        <svg className="w-10 h-10 mb-2 mx-auto" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path>
        </svg>
      </div>
      <span className="text-[10px] uppercase font-black tracking-widest pointer-events-none relative z-10">
        {isDragging ? 'SUELTA AQUI' : 'ARRASTRA IMAGEN'}
      </span>
      {alt && <span className="text-[8px] mt-1 opacity-50 font-mono pointer-events-none uppercase max-w-full truncate px-2 relative z-10">{alt}</span>}
    </div>
  );
};

export default AssetImage;

import React, { useState } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import Home from './views/Home.tsx';
import Community from './views/Community.tsx';
import Introduction from './views/Introduction.tsx';
import Components from './views/Components.tsx';
import Tools from './views/Tools.tsx';
import Glossary from './views/Glossary.tsx';
import Credits from './views/Credits.tsx';
import { dbHelpers } from './components/AssetImage.tsx';

const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const location = useLocation();

  const menuItems = [
    { path: '/', label: 'INICIO' },
    { path: '/comunidad', label: 'COMUNIDAD' },
    { path: '/introduccion', label: 'INTRODUCCIÓN' },
    { path: '/componentes', label: 'HARDWARE' },
    { path: '/herramientas', label: 'HERRAMIENTAS' },
    { path: '/glosario', label: 'GLOSARIO' },
    { path: '/creditos', label: 'CRÉDITOS' },
  ];

  const handleExportImages = async () => {
    if (!confirm("Esto descargará un archivo 'permanentImages.ts' con todas las imágenes que has colocado. ¿Deseas continuar?")) return;

    try {
      const allImages = await dbHelpers.getAll();
      const count = Object.keys(allImages).length;

      if (count === 0) {
        alert("No has subido ninguna imagen todavía.");
        return;
      }

      const fileContent = `// ARCHIVO GENERADO AUTOMÁTICAMENTE
// Reemplaza el contenido de 'utils/permanentImages.ts' con este código
// para que tus imágenes queden guardadas para siempre en la web.

export const PERMANENT_IMAGES: Record<string, string> = ${JSON.stringify(allImages, null, 2)};
`;

      const blob = new Blob([fileContent], { type: 'text/typescript' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'permanentImages.ts';
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);

      alert(`¡Archivo generado con ${count} imágenes! Ahora reemplaza el archivo 'utils/permanentImages.ts' con el que acabas de descargar.`);

    } catch (error) {
      console.error(error);
      alert("Hubo un error generando el archivo.");
    }
  };

  return (
    <div className="min-h-screen bg-[#fafafa] text-slate-900 selection:bg-blue-600 selection:text-white">
      {/* Sidebar de Índice */}
      <div className={`fixed top-0 left-0 h-full w-80 bg-white border-r border-slate-200 z-[5000] transition-transform duration-500 p-10 ${isMenuOpen ? 'translate-x-0' : '-translate-x-full shadow-2xl'}`}>
        <div className="flex justify-between items-center mb-12 border-b border-slate-100 pb-4">
          <h2 className="text-xl font-black uppercase tracking-tight text-blue-600">Índice General</h2>
          <button onClick={() => setIsMenuOpen(false)} className="text-3xl font-light hover:text-blue-600 transition-colors">×</button>
        </div>
        <nav className="flex flex-col gap-4">
          {menuItems.map((item) => (
            <Link 
              key={item.path} 
              to={item.path} 
              className={`text-base font-bold hover:text-blue-600 transition-all py-2 px-4 rounded-lg ${location.pathname === item.path ? 'bg-blue-50 text-blue-600' : 'text-slate-600 hover:bg-slate-50'}`}
              onClick={() => setIsMenuOpen(false)}
            >
              {item.label}
            </Link>
          ))}
        </nav>
      </div>

      {isMenuOpen && (
        <div className="fixed inset-0 bg-slate-900/20 backdrop-blur-sm z-[4999]" onClick={() => setIsMenuOpen(false)} />
      )}

      {/* Cabecera Profesional */}
      <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b-2 border-blue-600 py-4 px-10 shadow-sm">
        <div className="max-w-[1400px] mx-auto flex items-center justify-between">
          <div className="flex items-center gap-6">
            <button className="text-2xl p-2 hover:bg-slate-100 rounded-lg transition-colors" onClick={() => setIsMenuOpen(true)}>
              ☰
            </button>
            <div className="hidden md:block h-8 w-[1px] bg-slate-200"></div>
            <div>
              <h1 className="text-lg font-black tracking-tight uppercase text-slate-800">MANUAL <span className="text-blue-600">INTERACTIVO</span></h1>
              <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">U.E.E Jorge Semidey | PNF Informática</div>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-6">
            {menuItems.map((item) => (
              <Link 
                key={item.path} 
                to={item.path} 
                className={`text-[11px] font-extrabold uppercase tracking-wider transition-colors hover:text-blue-600 ${location.pathname === item.path ? 'text-blue-600' : 'text-slate-500'}`}
              >
                {item.label}
              </Link>
            ))}
          </div>
        </div>
      </header>

      <main className="max-w-[1200px] mx-auto py-12 px-6 md:px-12 bg-white my-8 border border-slate-200 shadow-sm rounded-xl min-h-screen">
        {children}
      </main>

      <footer className="bg-white border-t border-slate-100 py-12 px-10">
        <div className="max-w-[1200px] mx-auto grid grid-cols-1 md:grid-cols-3 gap-8 text-[11px] font-bold uppercase tracking-widest text-slate-400">
           <div>
             <p className="mb-1 text-blue-600 font-black">Sede Institucional</p>
             <p className="text-slate-600">U.E.E "Jorge Semidey" - Maracay</p>
           </div>
           <div className="md:text-center">
             <p className="mb-1 text-blue-600 font-black">Proyecto Académico</p>
             <p className="text-slate-600">UPT Aragua "Federico Brito Figueroa"</p>
             <button onClick={handleExportImages} className="mt-4 text-[10px] bg-slate-100 hover:bg-blue-600 hover:text-white px-3 py-2 rounded transition-colors flex items-center gap-2 mx-auto">
               ⚙️ DESCARGAR CÓDIGO DE IMÁGENES
             </button>
           </div>
           <div className="md:text-right">
             <p className="mb-1 text-blue-600 font-black">Copyright</p>
             <p className="text-slate-600">© 2025 Soberanía Tecnológica</p>
           </div>
        </div>
      </footer>
    </div>
  );
};

