          <Route path="/introduccion" element={<Introduction />} />
          <Route path="/componentes" element={<Components />} />
          <Route path="/herramientas" element={<Tools />} />
          <Route path="/glosario" element={<Glossary />} />
          <Route path="/creditos" element={<Credits />} />
